#include <bits/stdc++.h>
using namespace std;

const int N=5010,M=N<<2,INF=1e8;

int n,k,a[N][N],s,t;
int head[N],ver[M],edge[M],val[M],nxt[M],tot=1;
int d[N],dis[N],last[N];
bool inq[N];

int cal(int x,int y){
    return (x-1)*n+y;
}

void add(int x,int y,int c,int w){
    ver[++tot]=y,edge[tot]=c,val[tot]=w,nxt[tot]=head[x],head[x]=tot;
    ver[++tot]=x,edge[tot]=0,val[tot]=-w,nxt[tot]=head[y],head[y]=tot;
}

bool bfs(){
    memset(dis,0xcf,sizeof(dis));
    memset(d,0,sizeof(d));
    memset(inq,0,sizeof(inq));
    queue<int> q;
    q.push(s),d[s]=INF,dis[s]=0,inq[s]=1;
    while(q.size()){
        int x=q.front();
        q.pop(),inq[x]=0;
        for(int i=head[x],y;i;i=nxt[i])
            if(edge[i] && dis[y=ver[i]]<(dis[x]+val[i])*min(edge[i],d[x])){
                d[y]=min(d[x],edge[i]),dis[y]=(dis[x]+val[i]),last[y]=i;
                if(!inq[y])
                    q.push(y),inq[y]=1;
            }
    }
    return dis[t]>0;
}

void update(){
    int p=t;
    while(p!=s){
        edge[last[p]]-=d[t],edge[last[p]^1]+=d[t];
        p=ver[last[p]^1];
    }
}

int main(){
    scanf("%d%d",&n,&k);
    for(int i=1;i<=n;i++)
        for(int j=1;j<=n;j++)
            scanf("%d",&a[i][j]);
    for(int i=1;i<=n;i++)
        for(int j=1;j<=n;j++){
            add(cal(i,j),cal(i,j)+n*n,1,a[i][j]);
            add(cal(i,j),cal(i,j)+n*n,k-1,0);
            if(i<n)
                add(cal(i,j)+n*n,cal(i+1,j),k,0);
            if(j<n)
                add(cal(i,j)+n*n,cal(i,j+1),k,0);
        }
    s=1,t=n*n*2;
    int flow,max_flow=0,ans=0;
    while(bfs()){
        ans+=dis[t]*d[t];
        update();
    }
    printf("%d",ans);
    return 0;
}
